<template><AdminPage title="评论管理" kicker="Community" hint="按内容、用户或影片定位评论，违规内容采用逻辑删除。"><template #actions><el-input v-model="query.keyword" clearable placeholder="搜索评论内容" @keyup.enter="load"/><button class="pill-button is-active" @click="search">查询</button></template><div class="table-shell surface-card overflow-hidden p-4"><el-table :data="records" v-loading="loading"><el-table-column prop="nickname" label="用户" width="140"/><el-table-column prop="title" label="影片" min-width="180"/><el-table-column prop="content" label="评论内容" min-width="320" show-overflow-tooltip/><el-table-column prop="createTime" label="发布时间" width="180"/><el-table-column label="操作" width="100"><template #default="{row}"><el-button link type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><AdminPagination v-model:page="query.pageNum" :total="total" @change="load"/></div></AdminPage></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{pageComments,deleteComment}from'@/api/adminManagement';import AdminPage from'@/components/admin/AdminPage.vue';import AdminPagination from'@/components/admin/AdminPagination.vue';const records=ref([]),total=ref(0),loading=ref(false),query=reactive({keyword:'',pageNum:1,pageSize:10});async function load(){loading.value=true;try{const r=await pageComments(query);records.value=r.data.records;total.value=r.data.total}finally{loading.value=false}}function search(){query.pageNum=1;load()}async function remove(row){await ElMessageBox.confirm(`确认删除“${row.nickname}”的评论？`,'删除评论',{type:'warning'});await deleteComment(row.id);ElMessage.success('评论已删除');load()}onMounted(load)</script>
